namespace sv_cfc6801a1965418aad3d650e5b949f59.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public IReadOnlyList<Warehouse> Warehouses { get; } = new List<Warehouse>
    {
        new("WH-001", "Warehouse A — Main Distribution"),
        new("WH-002", "Warehouse B — East Regional"),
        new("WH-003", "Warehouse C — West Regional"),
        new("WH-004", "Warehouse D — Returns Processing")
    };

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record Warehouse(string Id, string Name);

namespace sv_cfc6801a1965418aad3d650e5b949f59.Services;

public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private Timer? _timer;
    private int _subscriberCount;
    private readonly Lock _lock = new();

    public int CurrentLowStockCount { get; private set; }

    public event Action? OnAlertUpdated;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning the count of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }

    public void StartPolling()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1)
            {
                _timer = new Timer(PollCallback, null, TimeSpan.Zero, TimeSpan.FromSeconds(10));
            }
        }
    }

    public void StopPolling()
    {
        lock (_lock)
        {
            _subscriberCount--;
            if (_subscriberCount <= 0)
            {
                _subscriberCount = 0;
                _timer?.Dispose();
                _timer = null;
            }
        }
    }

    private async void PollCallback(object? state)
    {
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        CurrentLowStockCount = count;
        OnAlertUpdated?.Invoke();
    }

    private async void HandleWarehouseChanged()
    {
        // Immediately refresh when warehouse changes
        var count = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        CurrentLowStockCount = count;
        OnAlertUpdated?.Invoke();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        _timer?.Dispose();
    }
}

