@page "/dashboard"
@using sv_cfc6801a1965418aad3d650e5b949f59.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">
            @WarehouseState.Warehouses.FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId)?.Name
            <small class="text-muted">(@WarehouseState.CurrentWarehouseId)</small>
        </p>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card @(AlertService.CurrentLowStockCount > 10 ? "border-danger" : AlertService.CurrentLowStockCount > 5 ? "border-warning" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="display-4 @(AlertService.CurrentLowStockCount > 10 ? "text-danger" : AlertService.CurrentLowStockCount > 5 ? "text-warning" : "text-success")">
                    @AlertService.CurrentLowStockCount
                </p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6 text-info">Active</p>
                <p class="text-muted">refreshing every 10 seconds</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Updated</h5>
                <p class="display-6">@_lastUpdated.ToString("HH:mm:ss")</p>
                <p class="text-muted">local time</p>
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime _lastUpdated = DateTime.Now;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
        AlertService.OnAlertUpdated += OnAlertUpdated;
        AlertService.StartPolling();
    }

    private void OnStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void OnAlertUpdated()
    {
        _lastUpdated = DateTime.Now;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
        AlertService.OnAlertUpdated -= OnAlertUpdated;
        AlertService.StopPolling();
    }
}

